(window.webpackJsonp=window.webpackJsonp||[]).push([[139],{766:function(n,e){n.exports="\x3c!--\ntitle: 06-文件操作\nsort:\n--\x3e \n\n> 奇妙的文件管理\n\n## 文件搜索\n\n`locate [name]` \n\n> 搜寻所有含有name的路径\n>\n> 如找不到此命令,安装`mlocate or slocate`\n>\n> 新安装需要更新数据库`updatedb`\n\n`find [path] -[option] [keyword]`\n\n> 与`wc`连用\n>\n> `find ~ -type d | wc -l`\n>\n> 测试条件\n>\n> `find ~ -type f -name \"*.png\" -size +1M`\n>\n> 批量删除\n>\n> `find ~ -type f -name \"nohup.out\" -print`\n>\n> `find ~ -type f -name \"nohup.out\" -delete`\n\n### 调用命令\n\n`-exec`\n\n> `find ~ -type f -exec ls -l '{}' ';'`\n>\n> {}: 当前路径名 ; 命令的结束 \n>\n> `find ~ -type f -ok ls -l '{}' ';'`\n>\n> 每次运行都会询问\n\n`xargs`\n\n> `find ~ | xargs ls -l`\n>\n> 与上相同\n\n## 训练\n\n```bash\nmkdir -p dir-{00{1..9},0{10..99},100}\ntouch dir-{00{1..9},0{10..99},100}/file-{A..Z}\n```\n\n## 文本处理\n\n- cat\n\n  > `-ns`: 添加行号|不显示连续空白行\n\n- sort\n\n  > `-nr`: 字符串数值排序|倒序\n\n- diff\n\n  > 差异"}}]);